import { Test, TestingModule } from '@nestjs/testing';
import { AuthService } from './auth.service';
import { UserService } from '../../modules/user/user.service';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { CACHE_MANAGER } from '@nestjs/cache-manager';
import { getRepositoryToken } from '@nestjs/typeorm';
import { User } from '../../modules/user/entities/user.entity';
import { RefreshToken } from './entities/refresh-token.entity';
import { Repository } from 'typeorm';
import { UnauthorizedException } from '@nestjs/common';

// Mock bcrypt at top level
jest.mock('bcrypt', () => ({
  compare: jest.fn(),
  hash: jest.fn().mockResolvedValue('hashedpassword'),
  genSalt: jest.fn().mockResolvedValue('salt'),
}));

// eslint-disable-next-line @typescript-eslint/no-require-imports
const bcrypt = require('bcrypt');

describe('AuthService', () => {
  let service: AuthService;
  let userService: UserService;
  let jwtService: JwtService;
  let tokenRepo: Repository<RefreshToken>;

  const mockUser = {
    user_id: 1,
    username: 'testuser',
    password: 'hashedpassword',
    primaryOrganizationId: 1,
  };

  const mockQueryBuilder = {
    addSelect: jest.fn().mockReturnThis(),
    leftJoinAndSelect: jest.fn().mockReturnThis(),
    where: jest.fn().mockReturnThis(),
    getOne: jest.fn().mockResolvedValue(mockUser),
  };

  const mockUserRepo = {
    createQueryBuilder: jest.fn().mockReturnValue(mockQueryBuilder),
  };

  const mockTokenRepo = {
    create: jest.fn(),
    save: jest.fn(),
    findOne: jest.fn(),
    update: jest.fn(),
  };

  beforeEach(async () => {
    // Reset bcrypt mocks
    bcrypt.compare.mockResolvedValue(true);

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AuthService,
        {
          provide: UserService,
          useValue: {
            findOneByUsername: jest.fn(),
            create: jest.fn(),
            findOne: jest.fn(),
          },
        },
        {
          provide: JwtService,
          useValue: {
            signAsync: jest.fn().mockResolvedValue('jwt_token'),
            decode: jest.fn(),
          },
        },
        {
          provide: ConfigService,
          useValue: {
            get: jest.fn().mockImplementation((key: string) => {
              if (key.includes('EXPIRATION')) return '1h';
              return 'secret';
            }),
          },
        },
        {
          provide: CACHE_MANAGER,
          useValue: {
            set: jest.fn(),
          },
        },
        {
          provide: getRepositoryToken(User),
          useValue: mockUserRepo,
        },
        {
          provide: getRepositoryToken(RefreshToken),
          useValue: mockTokenRepo,
        },
      ],
    }).compile();

    service = module.get<AuthService>(AuthService);
    userService = module.get<UserService>(UserService);
    jwtService = module.get<JwtService>(JwtService);
    tokenRepo = module.get(getRepositoryToken(RefreshToken));
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  describe('validateUser', () => {
    it('should return user without password if validation succeeds', async () => {
      const result = await service.validateUser('testuser', 'password');
      expect(result).toBeDefined();
      expect(result).not.toHaveProperty('password');
      expect(result.username).toBe('testuser');
    });

    it('should return null if user not found', async () => {
      mockQueryBuilder.getOne.mockResolvedValueOnce(null);
      const result = await service.validateUser('unknown', 'password');
      expect(result).toBeNull();
    });

    it('should return null if password mismatch', async () => {
      bcrypt.compare.mockResolvedValueOnce(false);
      const result = await service.validateUser('testuser', 'wrongpassword');
      expect(result).toBeNull();
    });
  });

  describe('login', () => {
    it('should return access and refresh tokens', async () => {
      mockTokenRepo.create.mockReturnValue({ id: 1 });
      mockTokenRepo.save.mockResolvedValue({ id: 1 });

      const result = await service.login(mockUser);

      expect(result).toHaveProperty('access_token');
      expect(result).toHaveProperty('refresh_token');
      expect(mockTokenRepo.save).toHaveBeenCalled();
    });
  });

  describe('register', () => {
    it('should register a new user', async () => {
      (userService.findOneByUsername as jest.Mock).mockResolvedValue(null);
      (userService.create as jest.Mock).mockResolvedValue(mockUser);

      const dto = {
        username: 'newuser',
        password: 'password',
        email: 'test@example.com',
        firstName: 'Test',
        lastName: 'User',
      };

      const result = await service.register(dto);
      expect(result).toBeDefined();
      expect(userService.create).toHaveBeenCalled();
    });
  });

  describe('refreshToken', () => {
    it('should return new tokens if valid', async () => {
      const mockStoredToken = {
        tokenHash: 'somehash',
        isRevoked: false,
        expiresAt: new Date(Date.now() + 10000),
      };
      mockTokenRepo.findOne.mockResolvedValue(mockStoredToken);
      (userService.findOne as jest.Mock).mockResolvedValue(mockUser);

      const result = await service.refreshToken(1, 'valid_refresh_token');

      expect(result.access_token).toBeDefined();
      expect(result.refresh_token).toBeDefined();
      // Should mark old token as revoked
      expect(mockTokenRepo.save).toHaveBeenCalledWith(
        expect.objectContaining({ isRevoked: true })
      );
    });

    it('should throw UnauthorizedException if token revoked', async () => {
      const mockStoredToken = {
        tokenHash: 'somehash',
        isRevoked: true,
        expiresAt: new Date(Date.now() + 10000),
      };
      mockTokenRepo.findOne.mockResolvedValue(mockStoredToken);

      await expect(service.refreshToken(1, 'revoked_token')).rejects.toThrow(
        UnauthorizedException
      );
    });

    it('should allow refresh within 30s grace period if already revoked', async () => {
      const updatedAt = new Date(Date.now() - 5000); // 5 seconds ago
      const mockStoredToken = {
        tokenHash: 'somehash',
        isRevoked: true,
        updatedAt: updatedAt,
        replacedByToken: 'new_token_hash',
        expiresAt: new Date(Date.now() + 10000),
      };
      mockTokenRepo.findOne.mockResolvedValue(mockStoredToken);
      (userService.findOne as jest.Mock).mockResolvedValue(mockUser);
      mockTokenRepo.create.mockReturnValue({ token_id: 2 });
      mockTokenRepo.save.mockResolvedValue({ token_id: 2 });

      const result = await service.refreshToken(1, 'valid_refresh_token');

      expect(result.access_token).toBeDefined();
      expect(result.refresh_token).toBeDefined();
      // Should not call revokeAllUserTokens
      expect(mockTokenRepo.update).not.toHaveBeenCalled();
    });

    it('should throw UnauthorizedException if token revoked more than 30s ago', async () => {
      const updatedAt = new Date(Date.now() - 35000); // 35 seconds ago
      const mockStoredToken = {
        tokenHash: 'somehash',
        isRevoked: true,
        updatedAt: updatedAt,
        replacedByToken: 'new_token_hash',
        expiresAt: new Date(Date.now() + 10000),
      };
      mockTokenRepo.findOne.mockResolvedValue(mockStoredToken);

      await expect(service.refreshToken(1, 'revoked_token')).rejects.toThrow(
        UnauthorizedException
      );
    });
  });
});

// File: src/common/auth/strategies/jwt-refresh.strategy.ts
// บันทึกการแก้ไข: Strategy สำหรับ Refresh Token (T1.2)
// บันทึกการแก้ไข: แก้ไข TS2345 โดยยืนยันค่า secretOrKey ด้วย ! (Non-null assertion)

import { ExtractJwt, Strategy } from 'passport-jwt';
import { PassportStrategy } from '@nestjs/passport';
import { Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { Request } from 'express';
import type { JwtPayload } from './jwt.strategy';

@Injectable()
export class JwtRefreshStrategy extends PassportStrategy(
  Strategy,
  'jwt-refresh'
) {
  constructor(configService: ConfigService) {
    super({
      jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
      ignoreExpiration: false,
      // ✅ Fix: ใส่ ! เพื่อบอก TS ว่าค่านี้มีอยู่จริง (จาก env validation)
      secretOrKey: configService.get<string>('JWT_REFRESH_SECRET')!,
      passReqToCallback: true,
    });
  }

  async validate(req: Request, payload: JwtPayload) {
    const refreshToken = ExtractJwt.fromAuthHeaderAsBearerToken()(req);
    return {
      ...payload,
      refreshToken,
    };
  }
}

import { Test, TestingModule } from '@nestjs/testing';
import { FileStorageService } from './file-storage.service';
import { getRepositoryToken } from '@nestjs/typeorm';
import { Attachment } from './entities/attachment.entity';
import { ConfigService } from '@nestjs/config';
import * as fs from 'fs-extra';
import {
  BadRequestException,
  NotFoundException,
  ForbiddenException,
} from '@nestjs/common';
import { Repository } from 'typeorm';

// Mock fs-extra
jest.mock('fs-extra');

describe('FileStorageService', () => {
  let service: FileStorageService;
  let attachmentRepo: Repository<Attachment>;

  const mockAttachment = {
    id: 1,
    originalFilename: 'test.pdf',
    storedFilename: 'uuid.pdf',
    filePath: '/permanent/2024/12/uuid.pdf',
    fileSize: 1024,
    uploadedByUserId: 1,
  } as Attachment;

  const mockFile = {
    originalname: 'test.pdf',
    mimetype: 'application/pdf',
    size: 1024,
    buffer: Buffer.from('test-content'),
  } as Express.Multer.File;

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        FileStorageService,
        {
          provide: getRepositoryToken(Attachment),
          useValue: {
            create: jest.fn().mockReturnValue(mockAttachment),
            save: jest.fn().mockResolvedValue(mockAttachment),
            find: jest.fn(),
            findOne: jest.fn(),
            remove: jest.fn(),
          },
        },
        {
          provide: ConfigService,
          useValue: {
            get: jest.fn((key) => {
              if (key === 'NODE_ENV') return 'test';
              return null;
            }),
          },
        },
      ],
    }).compile();

    service = module.get<FileStorageService>(FileStorageService);
    attachmentRepo = module.get(getRepositoryToken(Attachment));

    jest.clearAllMocks();
    (fs.ensureDirSync as unknown as jest.Mock).mockReturnValue(true);
    (fs.writeFile as unknown as jest.Mock).mockResolvedValue(undefined);
    (fs.pathExists as unknown as jest.Mock).mockResolvedValue(true);
    (fs.move as unknown as jest.Mock).mockResolvedValue(undefined);
    (fs.remove as unknown as jest.Mock).mockResolvedValue(undefined);
    (fs.readFile as unknown as jest.Mock).mockResolvedValue(
      Buffer.from('test')
    );
    (fs.stat as unknown as jest.Mock).mockResolvedValue({ size: 1024 });
    (fs.ensureDir as unknown as jest.Mock).mockResolvedValue(undefined);
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  describe('upload', () => {
    it('should save file to temp and create DB record', async () => {
      const result = await service.upload(mockFile, 1);

      expect(fs.writeFile).toHaveBeenCalled();
      expect(attachmentRepo.create).toHaveBeenCalled();
      expect(attachmentRepo.save).toHaveBeenCalled();
      expect(result).toBeDefined();
    });

    it('should throw BadRequestException if write fails', async () => {
      (fs.writeFile as unknown as jest.Mock).mockRejectedValueOnce(
        new Error('Write error')
      );
      await expect(service.upload(mockFile, 1)).rejects.toThrow(
        BadRequestException
      );
    });
  });

  describe('commit', () => {
    it('should move files to permanent storage', async () => {
      const tempIds = ['uuid-1'];
      const mockAttachments = [
        {
          ...mockAttachment,
          isTemporary: true,
          tempId: 'uuid-1',
          filePath: '/temp/uuid.pdf',
        },
      ];

      (attachmentRepo.find as jest.Mock).mockResolvedValue(mockAttachments);

      await service.commit(tempIds);

      expect(fs.ensureDir).toHaveBeenCalled();
      expect(fs.move).toHaveBeenCalled();
      expect(attachmentRepo.save).toHaveBeenCalled();
    });

    it('should show warning if file counts mismatch', async () => {
      (attachmentRepo.find as jest.Mock).mockResolvedValue([]);
      await expect(service.commit(['uuid-1'])).rejects.toThrow(
        NotFoundException
      );
    });
  });

  describe('delete', () => {
    it('should delete file if user owns it', async () => {
      (attachmentRepo.findOne as jest.Mock).mockResolvedValue(mockAttachment);

      await service.delete(1, 1);

      expect(fs.remove).toHaveBeenCalled();
      expect(attachmentRepo.remove).toHaveBeenCalled();
    });

    it('should throw ForbiddenException if user does not own file', async () => {
      (attachmentRepo.findOne as jest.Mock).mockResolvedValue(mockAttachment);
      await expect(service.delete(1, 999)).rejects.toThrow(ForbiddenException);
    });
  });
});

import { DataSource } from 'typeorm';
import { databaseConfig } from '../../config/database.config';
import { seedOrganizations } from './organization.seed';
import { seedUsers } from './user.seed';

async function runSeeds() {
  const dataSource = new DataSource(databaseConfig as any);
  await dataSource.initialize();

  try {
    console.log('🌱 Seeding database...');

    await seedOrganizations(dataSource);
    await seedUsers(dataSource);

    console.log('✅ Seeding completed!');
  } catch (error) {
    console.error('❌ Seeding failed:', error);
  } finally {
    await dataSource.destroy();
  }
}

runSeeds();

import { DataSource } from 'typeorm';
import { User } from '../../modules/user/entities/user.entity';
import { Role, RoleScope } from '../../modules/user/entities/role.entity';
import { UserAssignment } from '../../modules/user/entities/user-assignment.entity';
import * as bcrypt from 'bcrypt';

export async function seedUsers(dataSource: DataSource) {
  const userRepo = dataSource.getRepository(User);
  const roleRepo = dataSource.getRepository(Role);
  const assignmentRepo = dataSource.getRepository(UserAssignment);

  // Create Roles
  const rolesData = [
    {
      roleName: 'Superadmin',
      scope: RoleScope.GLOBAL,
      description:
        'ผู้ดูแลระบบสูงสุด: สามารถทำทุกอย่างในระบบ, จัดการองค์กร, และจัดการข้อมูลหลักระดับ Global',
    },
    {
      roleName: 'Org Admin',
      scope: RoleScope.ORGANIZATION,
      description:
        'ผู้ดูแลองค์กร: จัดการผู้ใช้ในองค์กร, จัดการบทบาท / สิทธิ์ภายในองค์กร, และดูรายงานขององค์กร',
    },
    {
      roleName: 'Document Control',
      scope: RoleScope.ORGANIZATION,
      description:
        'ควบคุมเอกสารขององค์กร: เพิ่ม / แก้ไข / ลบเอกสาร, และกำหนดสิทธิ์เอกสารภายในองค์กร',
    },
    {
      roleName: 'Editor',
      scope: RoleScope.PROJECT,
      description:
        'ผู้แก้ไขเอกสารขององค์กร: เพิ่ม / แก้ไขเอกสารที่ได้รับมอบหมาย',
    },
    {
      roleName: 'Viewer',
      scope: RoleScope.PROJECT,
      description: 'ผู้ดูเอกสารขององค์กร: ดูเอกสารที่มีสิทธิ์เข้าถึงเท่านั้น',
    },
    {
      roleName: 'Project Manager',
      scope: RoleScope.PROJECT,
      description:
        'ผู้จัดการโครงการ: จัดการสมาชิกในโครงการ, สร้าง / จัดการสัญญาในโครงการ, และดูรายงานโครงการ',
    },
    {
      roleName: 'Contract Admin',
      scope: RoleScope.CONTRACT,
      description:
        'ผู้ดูแลสัญญา: จัดการสมาชิกในสัญญา, สร้าง / จัดการข้อมูลหลักเฉพาะสัญญา, และอนุมัติเอกสารในสัญญา',
    },
  ];

  const roleMap = new Map();
  for (const r of rolesData) {
    let role = await roleRepo.findOneBy({ roleName: r.roleName });
    if (!role) {
      // @ts-ignore
      role = await roleRepo.save(roleRepo.create(r));
    }
    roleMap.set(r.roleName, role);
  }

  // Create Users
  const usersData = [
    {
      username: 'superadmin',
      email: 'superadmin@example.com',
      firstName: 'Super',
      lastName: 'Admin',
      roleName: 'Superadmin',
    },
    {
      username: 'admin',
      email: 'admin@example.com',
      firstName: 'Admin',
      lastName: 'คคง.',
      roleName: 'Org Admin',
    },
    {
      username: 'editor01',
      email: 'editor01@example.com',
      firstName: 'DC',
      lastName: 'C1',
      roleName: 'Editor',
    },
    {
      username: 'viewer01',
      email: 'viewer01@example.com',
      firstName: 'Viewer',
      lastName: 'สคฉ.03',
      roleName: 'Viewer',
    },
  ];

  const salt = await bcrypt.genSalt();
  const password = await bcrypt.hash('password123', salt); // Default password

  for (const u of usersData) {
    let user = await userRepo.findOneBy({ username: u.username });
    if (!user) {
      user = userRepo.create({
        username: u.username,
        email: u.email,
        firstName: u.firstName,
        lastName: u.lastName,
        password, // Fixed: password instead of passwordHash
      });
      user = await userRepo.save(user);

      // Create Assignment
      const role = roleMap.get(u.roleName);
      if (role) {
        const assignment = assignmentRepo.create({
          user,
          role,
          assignedAt: new Date(),
        });
        await assignmentRepo.save(assignment);
      }
    }
  }
}

// src/database/seeds/workflow-definitions.seed.ts

import { DataSource } from 'typeorm';
import { WorkflowDefinition } from '../../modules/workflow-engine/entities/workflow-definition.entity';
import { WorkflowDslService } from '../../modules/workflow-engine/workflow-dsl.service';

export const seedWorkflowDefinitions = async (dataSource: DataSource) => {
  const repo = dataSource.getRepository(WorkflowDefinition);
  const dslService = new WorkflowDslService();

  // 1. RFA Workflow (Standard)
  const rfaDsl = {
    workflow: 'RFA_FLOW_V1', // [FIX] เปลี่ยนชื่อให้ตรงกับค่าใน RfaWorkflowService
    version: 1,
    description: 'Standard RFA Approval Workflow',
    states: [
      {
        name: 'DRAFT',
        initial: true,
        on: {
          SUBMIT: {
            to: 'IN_REVIEW',
            require: { role: 'Editor' }, // [FIX] แก้ไข Syntax เป็น Object
          },
        },
      },
      {
        name: 'IN_REVIEW',
        on: {
          APPROVE_1: {
            to: 'APPROVED', // [FIX] ชี้ไปที่ State ที่มีอยู่จริง
            require: { role: 'Contract Admin' },
            condition: "context.priority === 'HIGH'",
          },
          APPROVE_2: {
            to: 'APPROVED', // [FIX] ชี้ไปที่ State ที่มีอยู่จริง
            require: { role: 'Contract Admin' },
            condition: "context.priority === 'NORMAL'",
          },
          REJECT: {
            to: 'REJECTED',
            require: { role: 'Contract Admin' },
          },
          COMMENT: {
            to: 'DRAFT',
            require: { role: 'Contract Admin' },
          }, // ส่งกลับแก้ไข
        },
      },
      { name: 'APPROVED', terminal: true },
      { name: 'REJECTED', terminal: true },
    ],
  };

  // 2. Circulation Workflow
  const circulationDsl = {
    workflow: 'CIRCULATION_INTERNAL_V1', // [FIX] เปลี่ยนชื่อให้ตรงกับค่าใน CirculationWorkflowService
    version: 1,
    description: 'Internal Document Circulation',
    states: [
      {
        name: 'OPEN',
        initial: true,
        on: {
          START: {
            // [FIX] เปลี่ยนชื่อ Action ให้ตรงกับที่ Service เรียกใช้ ('START')
            to: 'IN_REVIEW',
          },
        },
      },
      {
        name: 'IN_REVIEW',
        on: {
          COMPLETE_TASK: {
            // [FIX] เปลี่ยนให้สอดคล้องกับ Action ที่ใช้จริง
            to: 'COMPLETED',
          },
          CANCEL: { to: 'CANCELLED' },
        },
      },
      { name: 'COMPLETED', terminal: true },
      { name: 'CANCELLED', terminal: true },
    ],
  };

  // 3. Correspondence Workflow (Optional - ถ้ามี)
  const correspondenceDsl = {
    workflow: 'CORRESPONDENCE_FLOW_V1',
    version: 1,
    description: 'Standard Correspondence Routing',
    states: [
      {
        name: 'DRAFT',
        initial: true,
        on: { SUBMIT: { to: 'IN_REVIEW' } },
      },
      {
        name: 'IN_REVIEW',
        on: {
          APPROVE: { to: 'APPROVED' },
          REJECT: { to: 'REJECTED' },
        },
      },
      { name: 'APPROVED', terminal: true },
      { name: 'REJECTED', terminal: true },
    ],
  };

  const workflows = [rfaDsl, circulationDsl, correspondenceDsl];

  for (const dsl of workflows) {
    const exists = await repo.findOne({
      where: { workflow_code: dsl.workflow, version: dsl.version },
    });

    if (!exists) {
      try {
        // Compile เพื่อ Validate และ Normalize ก่อนบันทึก
        const compiled = dslService.compile(
          dsl as unknown as import('../../modules/workflow-engine/workflow-dsl.service').RawWorkflowDSL
        );

        await repo.save(
          repo.create({
            workflow_code: dsl.workflow,
            version: dsl.version,
            description: dsl.description,
            dsl: dsl as unknown as Record<string, unknown>,
            compiled: compiled as unknown as Record<string, unknown>,
            is_active: true,
          })
        );
//         console.log(`✅ Seeded Workflow: ${dsl.workflow} v${dsl.version}`);
      } catch (error) {
//         console.error(`❌ Failed to seed workflow ${dsl.workflow}:`, error);
      }
    } else {
//       console.log(
//         `⏭️  Workflow already exists: ${dsl.workflow} v${dsl.version}`
//       );
    }
  }
};

import { Test, TestingModule } from '@nestjs/testing';
import { getRepositoryToken } from '@nestjs/typeorm';
import { DataSource } from 'typeorm';
import { CorrespondenceService } from './correspondence.service';
import { Correspondence } from './entities/correspondence.entity';
import { CorrespondenceRevision } from './entities/correspondence-revision.entity';
import { CorrespondenceType } from './entities/correspondence-type.entity';
import { CorrespondenceStatus } from './entities/correspondence-status.entity';
import { CorrespondenceReference } from './entities/correspondence-reference.entity';
import { Organization } from '../organization/entities/organization.entity';
import { CorrespondenceRecipient } from './entities/correspondence-recipient.entity';
import { DocumentNumberingService } from '../document-numbering/services/document-numbering.service';
import { JsonSchemaService } from '../json-schema/json-schema.service';
import { WorkflowEngineService } from '../workflow-engine/workflow-engine.service';
import { UserService } from '../user/user.service';
import { SearchService } from '../search/search.service';
import { FileStorageService } from '../../common/file-storage/file-storage.service';

