        templateUsed: 'test',
      });
      (auditRepo.save as jest.Mock).mockResolvedValue({ id: 2 });

      const result = await service.voidAndReplace({
        documentNumber: 'DOC-001',
        reason: 'test',
        replace: false,
      });
      expect(result.status).toBe('VOIDED');
      expect(auditRepo.save).toHaveBeenCalled();
    });

    it('cancelNumber should log cancellation', async () => {
      const auditRepo = module.get(getRepositoryToken(DocumentNumberAudit));
      (auditRepo.findOne as jest.Mock).mockResolvedValue({
        documentNumber: 'DOC-002',
        counterKey: {},
      });
      (auditRepo.save as jest.Mock).mockResolvedValue({ id: 3 });

      const result = await service.cancelNumber({
        documentNumber: 'DOC-002',
        reason: 'bad',
        projectId: 1,
      });
      expect(result.status).toBe('CANCELLED');
      expect(auditRepo.save).toHaveBeenCalled();
    });
  });
});

import {
  Entity,
  PrimaryGeneratedColumn,
  Column,
  CreateDateColumn,
  Index,
} from 'typeorm';

@Entity('document_number_audit')
@Index(['createdAt'])
@Index(['userId'])
@Index(['documentId'])
@Index(['status'])
@Index(['operation'])
@Index(['documentNumber'])
@Index(['reservationToken'])
export class DocumentNumberAudit {
  @PrimaryGeneratedColumn()
  id!: number;

  @Column({ name: 'document_id', nullable: true })
  documentId?: number;

  @Column({ name: 'document_number', length: 100 })
  documentNumber!: string;

  @Column({ name: 'counter_key', type: 'json' })
  counterKey!: Record<string, unknown> | unknown;

  @Column({ name: 'template_used', length: 200 })
  templateUsed!: string;

  @Column({
    name: 'operation',
    type: 'enum',
    enum: [
      'RESERVE',
      'CONFIRM',
      'CANCEL',
      'MANUAL_OVERRIDE',
      'VOID',
      'VOID_REPLACE',
      'GENERATE',
    ],
    default: 'CONFIRM',
  })
  operation!: string;

  @Column({
    name: 'status',
    type: 'enum',
    enum: ['RESERVED', 'CONFIRMED', 'CANCELLED', 'VOID', 'MANUAL'],
    nullable: true,
  })
  status?: string;

  @Column({ name: 'reservation_token', length: 36, nullable: true })
  reservationToken?: string;

  @Column({ name: 'idempotency_key', length: 36, nullable: true })
  idempotencyKey?: string;

  @Column({ name: 'originator_organization_id', nullable: true })
  originatorOrganizationId?: number;

  @Column({ name: 'recipient_organization_id', nullable: true })
  recipientOrganizationId?: number;

  @Column({ name: 'old_value', type: 'text', nullable: true })
  oldValue?: string;

  @Column({ name: 'new_value', type: 'text', nullable: true })
  newValue?: string;

  @Column({ name: 'metadata', type: 'json', nullable: true })
  metadata?: Record<string, unknown>;

  @Column({ name: 'user_id', nullable: true })
  userId?: number;

  @Column({ name: 'ip_address', length: 45, nullable: true })
  ipAddress?: string;

  @Column({ name: 'user_agent', type: 'text', nullable: true })
  userAgent?: string;

  @Column({ name: 'is_success', default: true })
  isSuccess!: boolean;

  @Column({ name: 'retry_count', default: 0 })
  retryCount!: number;

  @Column({ name: 'lock_wait_ms', nullable: true })
  lockWaitMs?: number;

  @Column({ name: 'total_duration_ms', nullable: true })
  totalDurationMs?: number;

  @Column({
    name: 'fallback_used',
    type: 'enum',
    enum: ['NONE', 'DB_LOCK', 'RETRY'],
    default: 'NONE',
  })
  fallbackUsed?: string;

  @CreateDateColumn({ name: 'created_at' })
  createdAt!: Date;
}

import { Injectable } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, IsNull } from 'typeorm';
import { DocumentNumberFormat } from '../entities/document-number-format.entity';
import { Project } from '../../project/entities/project.entity';
import { CorrespondenceType } from '../../correspondence/entities/correspondence-type.entity';
import { Organization } from '../../organization/entities/organization.entity';
import { Discipline } from '../../master/entities/discipline.entity';

export interface FormatOptions {
  projectId: number;
  correspondenceTypeId: number;
  subTypeId?: number;
  rfaTypeId?: number;
  disciplineId?: number;
  sequence: number;
  resetScope: string;
  year?: number;
  originatorOrganizationId: number;
  recipientOrganizationId?: number;
}

export interface DecodedTokens {
  [key: string]: string;
}

@Injectable()
export class FormatService {
  constructor(
    @InjectRepository(DocumentNumberFormat)
    private formatRepo: Repository<DocumentNumberFormat>,
    @InjectRepository(Project)
    private projectRepo: Repository<Project>,
    @InjectRepository(CorrespondenceType)
    private typeRepo: Repository<CorrespondenceType>,
    @InjectRepository(Organization)
    private orgRepo: Repository<Organization>,
    @InjectRepository(Discipline)
    private disciplineRepo: Repository<Discipline>
  ) {}

  async format(
    options: FormatOptions
  ): Promise<{ previewNumber: string; isDefault: boolean }> {
    const { template, isDefault } = await this.resolveFormatAndScope(options);
    const currentYear = options.year || new Date().getFullYear();
    const tokens = await this.resolveTokens(options, currentYear);

    const previewNumber = this.replaceTokens(
      template,
      tokens,
      options.sequence
    );
//     console.log(
      `[FormatService] Generated: "${previewNumber}" | Template: "${template}" | isDefault: ${isDefault}`
    );
    return { previewNumber, isDefault };
  }

  // --- Helpers ---

  private async resolveFormatAndScope(options: FormatOptions): Promise<{
    template: string;
    resetSequenceYearly: boolean;
    isDefault: boolean;
  }> {
    // 1. Specific Format
    const specificFormat = await this.formatRepo.findOne({
      where: {
        projectId: options.projectId,
        correspondenceTypeId: options.correspondenceTypeId,
      },
    });
    if (specificFormat)
      return {
        template: specificFormat.formatTemplate,
        resetSequenceYearly: specificFormat.resetSequenceYearly,
        isDefault: false,
      };

    // 2. Default Format
    const defaultFormat = await this.formatRepo.findOne({
      where: { projectId: options.projectId, correspondenceTypeId: IsNull() },
    });
    if (defaultFormat)
      return {
        template: defaultFormat.formatTemplate,
        resetSequenceYearly: defaultFormat.resetSequenceYearly,
        isDefault: true,
      };

    // 3. Fallback
    return {
      template: '{ORG}-{RECIPIENT}-{SEQ:4}-{YEAR:BE}',
      resetSequenceYearly: true,
      isDefault: true,
    };
  }

  private async resolveTokens(
    options: FormatOptions,
    year: number
  ): Promise<DecodedTokens> {
    const [project, type, recipientCode, disciplineCode, orgCode] =
      await Promise.all([
        this.projectRepo.findOne({
          where: { id: options.projectId },
          select: ['projectCode'],
        }),
        this.typeRepo.findOne({
          where: { id: options.correspondenceTypeId },
          select: ['typeCode'],
        }),
        this.resolveRecipientCode(options.recipientOrganizationId),
        this.resolveDisciplineCode(options.disciplineId),
        this.resolveOrgCode(options.originatorOrganizationId),
      ]);

    return {
      '{PROJECT}': project?.projectCode || 'PROJ',
      '{TYPE}': type?.typeCode || 'DOC',
      '{ORG}': orgCode,
      '{RECIPIENT}': recipientCode,
      '{DISCIPLINE}': disciplineCode,
      '{YEAR}': year.toString(),
      '{YEAR:BE}': (year + 543).toString(),
      '{REV}': '0',
    };
  }

  private replaceTokens(
    template: string,
    tokens: DecodedTokens,
    sequence: number
  ): string {
    let result = template;
    for (const [key, value] of Object.entries(tokens)) {
      result = result.replace(
        new RegExp(key.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'),
        value
      );
    }
    const seqMatch = result.match(/{SEQ:(\d+)}/);
    if (seqMatch) {
      const padding = Number(seqMatch[1]);
      result = result.replace(
        seqMatch[0],
        sequence.toString().padStart(padding, '0')
      );
    }
    return result;
  }

  private async resolveRecipientCode(recipientId?: number): Promise<string> {
    if (!recipientId) return 'GEN';
    const org = await this.orgRepo.findOne({
      where: { id: recipientId },
      select: ['organizationCode'],
    });
    return org ? org.organizationCode : 'GEN';
  }

  private async resolveOrgCode(orgId?: number): Promise<string> {
    if (!orgId) return 'GEN';
    const org = await this.orgRepo.findOne({
      where: { id: orgId },
      select: ['organizationCode'],
    });
    return org ? org.organizationCode : 'GEN';
  }

  private async resolveDisciplineCode(disciplineId?: number): Promise<string> {
    if (!disciplineId) return 'GEN';
    const discipline = await this.disciplineRepo.findOne({
      where: { id: disciplineId },
      select: ['disciplineCode'],
    });
    return discipline ? discipline.disciplineCode : 'GEN';
  }
}

