// File: src/modules/workflow-engine/workflow-event.service.ts

import { Injectable, Logger } from '@nestjs/common';
import { RawEvent } from './workflow-dsl.service';

// Interface สำหรับ External Services ที่จะมารับ Event ต่อ
// (ในอนาคตควรใช้ NestJS Event Emitter เพื่อ Decouple อย่างสมบูรณ์)
export interface WorkflowEventHandler {
  handleNotification(
    target: string,
    template: string,
    payload: Record<string, unknown>
  ): Promise<void>;
  handleWebhook(url: string, payload: Record<string, unknown>): Promise<void>;
  handleAutoAction(instanceId: string, action: string): Promise<void>;
}

@Injectable()
export class WorkflowEventService {
  private readonly logger = new Logger(WorkflowEventService.name);

  // สามารถ Inject NotificationService หรือ HttpService เข้ามาได้ตรงนี้
  // constructor(private readonly notificationService: NotificationService) {}

  /**
   * ประมวลผลรายการ Events ที่เกิดจากการเปลี่ยนสถานะ
   */
  dispatchEvents(
    instanceId: string,
    events: RawEvent[],
    context: Record<string, unknown>
  ) {
    if (!events || events.length === 0) return;

    this.logger.log(
      `Dispatching ${events.length} events for Instance ${instanceId}`
    );

    // ทำแบบ Async ไม่รอผล (Fire-and-forget) เพื่อไม่ให้กระทบ Response Time ของ User
    void Promise.allSettled(
      events.map((event) => this.processSingleEvent(instanceId, event, context))
    ).then((results) => {
      // Log errors if any
      results.forEach((res, idx) => {
        if (res.status === 'rejected') {
          this.logger.error(
            `Failed to process event [${idx}]: ${String(res.reason)}`
          );
        }
      });
    });
  }

  private async processSingleEvent(
    instanceId: string,
    event: RawEvent,
    context: Record<string, unknown>
  ) {
    try {
      switch (event.type) {
        case 'notify':
          this.handleNotify(event, context);
          break;
        case 'webhook':
          this.handleWebhook(event, context);
          break;
        case 'auto_action':
          // Logic สำหรับ Auto Transition (เช่น ถ้าผ่านเงื่อนไข ให้ไปต่อเลย)
          this.logger.log(`Auto Action triggered for ${instanceId}`);
          break;
        default:
          this.logger.warn(`Unknown event type: ${event.type}`);
      }
    } catch (error) {
      this.logger.error(
        `Error processing event ${event.type}: ${String(error)}`
      );
      throw error;
    }
  }

  // --- Handlers ---

  private handleNotify(event: RawEvent, _context: Record<string, unknown>) {
    // Mockup: ในของจริงจะเรียก NotificationService.send()
    // const recipients = this.resolveRecipients(event.target, context);
    this.logger.log(
      `[EVENT] Notify target: "${event.target}" | Template: "${event.template}"`
    );
  }

  private handleWebhook(event: RawEvent, _context: Record<string, unknown>) {
    // Mockup: เรียก HttpService.post()
    this.logger.log(
      `[EVENT] Webhook to: "${event.target}" | Payload: ${JSON.stringify(event.payload)}`
    );
  }
}

import { DataSource } from 'typeorm';
import { databaseConfig } from '../config/database.config';
import { Attachment } from '../common/file-storage/entities/attachment.entity';
import * as fs from 'fs-extra';
import * as path from 'path';

async function migrateStorage() {
  // Config override for script execution if needed
  const config = { ...databaseConfig, entities: [Attachment] };
  const dataSource = new DataSource(config as any);
  await dataSource.initialize();

  try {
    console.log('🚀 Starting Storage Migration v2...');
    const attachmentRepo = dataSource.getRepository(Attachment);

    // Find all permanent attachments
    const attachments = await attachmentRepo.find({
      where: { isTemporary: false },
    });
    console.log(`Found ${attachments.length} permanent attachments.`);

    let movedCount = 0;
    let errorCount = 0;
    let skippedCount = 0;

    // Define base permanent directory
    // Note: Adjust path based on execution context (e.g., from backend root)
    const permanentBaseDir =
      process.env.UPLOAD_PERMANENT_DIR ||
      path.join(process.cwd(), 'uploads', 'permanent');

    console.log(`Target Permanent Directory: ${permanentBaseDir}`);

    if (!fs.existsSync(permanentBaseDir)) {
      console.warn(
        `Base directory not found: ${permanentBaseDir}. Creating it...`
      );
      await fs.ensureDir(permanentBaseDir);
    }

    for (const att of attachments) {
      if (!att.filePath) {
        skippedCount++;
        continue;
      }

      const currentPath = att.filePath;
      if (!fs.existsSync(currentPath)) {
        console.warn(`File not found on disk: ${currentPath} (ID: ${att.id})`);
        errorCount++;
        continue;
      }

      // Check if already in new structure (contains /General/YYYY/MM or similar)
      const newStructureRegex =
        /permanent[\/\\](ContractDrawing|ShopDrawing|AsBuiltDrawing|General)[\/\\]\d{4}[\/\\]\d{2}/;
      if (newStructureRegex.test(currentPath)) {
        skippedCount++;
        continue;
      }

      // Determine target date
      const refDate = att.referenceDate
        ? new Date(att.referenceDate)
        : new Date(att.createdAt);
      if (isNaN(refDate.getTime())) {
        console.warn(`Invalid date for ID ${att.id}, skipping.`);
        errorCount++;
        continue;
      }

      const year = refDate.getFullYear().toString();
      const month = (refDate.getMonth() + 1).toString().padStart(2, '0');

      // Determine Doc Type (Default 'General' as we don't know easily without joins)
      const docType = 'General';

      const newDir = path.join(permanentBaseDir, docType, year, month);
      const newPath = path.join(newDir, att.storedFilename);

      if (path.resolve(currentPath) === path.resolve(newPath)) {
        skippedCount++;
        continue;
      }

      try {
        await fs.ensureDir(newDir);
        await fs.move(currentPath, newPath, { overwrite: true });

        // Update DB
        att.filePath = newPath;
        if (!att.referenceDate) {
          att.referenceDate = refDate;
        }
        await attachmentRepo.save(att);
        movedCount++;
        if (movedCount % 100 === 0) console.log(`Moved ${movedCount} files...`);
      } catch (err: unknown) {
        console.error(
          `Failed to move file ID ${att.id}:`,
          (err as Error).message
        );
        errorCount++;
      }
    }

    console.log(`Migration completed.`);
    console.log(`Moved: ${movedCount}`);
    console.log(`Skipped: ${skippedCount}`);
    console.log(`Errors: ${errorCount}`);
  } catch (error) {
    console.error('Migration failed:', error);
  } finally {
    await dataSource.destroy();
  }
}

migrateStorage();

