             projectId,
             correspondenceTypeId: documentTypeId,
             disciplineId,
             originatorOrganizationId: fromOrgId,
             recipientOrganizationId: toOrgId
         });
         setPreview({ number: res.previewNumber, isDefaultTemplate: res.isDefault });
